import './project1.css'

function Project1() {
    return (
      <div id="project1-body">
          <h4>Stranger's Things</h4>
          <p id="project1-description">
            Stranger's Thing's is a REACT CRUD application that allows users to register an accounbuy and sell 
            Built a REACT app that allows users to register an account, build fitness routines, and browse routines and
            exercises created by other users.Furthered understanding of user authentication, login and registration forms, and handling states in REACT.
          </p>
      </div>
    )
  }

export default Project1;
